```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet]
    public async Task<IActionResult> Get([FromUri] string url)
    {
        var request = new HttpRequestMessage(HttpMethod.Get, url);
        var response = await _httpClient.SendAsync(request);

        response.EnsureSuccessStatusCode();
        return File(await response.Content.ReadAsStreamAsync(), response.Content.Headers.ContentType.MediaType);
    }

    [HttpPost]
    public async Task<IActionResult> Post([FromBody] object body, [FromUri] string url)
