import React, { useState, useCallback } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  const increment = useCallback(() => {
    setCount((prevCount) => prevCount + 1);
  }, []);

  const decrement = useCallback(() => {
    setCount((prevCount) => prevCount - 1);
  }, []);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={increment}>+</button>
      <button onClick={decrement}>-</button>
    </div>
  );
}

export default Counter;
```

In this example:

1. `useState` is used to create a state variable `count` and an `setCount` function to update it.
2. `useCallback` is used to memoize the `increment` and `decrement` functions so they are not recreated on every render.
3. The `increment` and `decrement` functions use the `setCount` function to update the state.

